2	// SMART SPAM DETECTOR — BACKGROUND SERVICE WORKER
3	// ============================================
4	
5	const DEFAULT_API_URL = "http://localhost:5000";
6	
7	// Get the API URL from storage
8	async function getApiUrl() {
9	  return new Promise((resolve) => {
10	    chrome.storage.local.get(["apiUrl"], (result) => {
11	      resolve(result.apiUrl || DEFAULT_API_URL);
12	    });
13	  });
14	}
15	
16	// Handle messages from content script
17	chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
18	  if (message.type === "ANALYZE_EMAIL") {
19	    analyzeEmail(message.text, message.gmail_spam, message.sender)
20	      .then((result) => sendResponse({ success: true, data: result }))
21	      .catch((err) => sendResponse({ success: false, error: err.message }));
22	    return true; // Keep message channel open for async response
23	  }
24	});
25	
26	// Call the prediction API
27	async function analyzeEmail(text, gmailSpam, senderInfo) {
28	  const apiUrl = await getApiUrl();
29	
30	  const response = await fetch(`${apiUrl}/predict`, {
31	    method: "POST",
32	    headers: { "Content-Type": "application/json" },
33	    body: JSON.stringify({
34	      text,
35	      gmail_spam: gmailSpam || false,
36	      sender: senderInfo || ""
37	    }),
38	  });
39	
40	  if (!response.ok) {
41	    throw new Error(`API returned ${response.status}`);
42	  }
43	
44	  return response.json();
45	}
