2	// SMART SPAM DETECTOR — POPUP SCRIPT
3	// ============================================
4	
5	const DEFAULT_API_URL = "http://localhost:5000";
6	
7	// ---- DOM ELEMENTS ----
8	const elements = {
9	  emailText: document.getElementById("emailText"),
10	  charCount: document.getElementById("charCount"),
11	  analyzeBtn: document.getElementById("analyzeBtn"),
12	  btnLoader: document.getElementById("btnLoader"),
13	  resultCard: document.getElementById("resultCard"),
14	  resultHeader: document.getElementById("resultHeader"),
15	  resultIcon: document.getElementById("resultIcon"),
16	  resultLabel: document.getElementById("resultLabel"),
17	  confidenceBar: document.getElementById("confidenceBar"),
18	  confidenceText: document.getElementById("confidenceText"),
19	  triggerWords: document.getElementById("triggerWords"),
20	  triggerTags: document.getElementById("triggerTags"),
21	  statusBadge: document.getElementById("statusBadge"),
22	  apiUrl: document.getElementById("apiUrl"),
23	  saveSettings: document.getElementById("saveSettings"),
24	  saveToast: document.getElementById("saveToast"),
25	  clearHistory: document.getElementById("clearHistory"),
26	  historyList: document.getElementById("historyList"),
27	};
28	
29	// ---- TAB NAVIGATION ----
30	document.querySelectorAll(".tab-btn").forEach((btn) => {
31	  btn.addEventListener("click", () => {
32	    document.querySelectorAll(".tab-btn").forEach((b) => b.classList.remove("active"));
33	    document.querySelectorAll(".tab-content").forEach((c) => c.classList.remove("active"));
34	    btn.classList.add("active");
35	    document.getElementById(`tab-${btn.dataset.tab}`).classList.add("active");
36	  });
37	});
