39	// ---- CHARACTER COUNT ----
40	elements.emailText.addEventListener("input", () => {
41	  elements.charCount.textContent = elements.emailText.value.length;
42	});
43	
44	// ---- GET API URL ----
45	async function getApiUrl() {
46	  return new Promise((resolve) => {
47	    if (typeof chrome !== "undefined" && chrome.storage) {
48	      chrome.storage.local.get(["apiUrl"], (result) => {
49	        resolve(result.apiUrl || DEFAULT_API_URL);
50	      });
51	    } else {
52	      resolve(DEFAULT_API_URL);
53	    }
54	  });
55	}
56	
57	// ---- CHECK API STATUS ----
58	async function checkApiStatus() {
59	  try {
60	    const apiUrl = await getApiUrl();
61	    const response = await fetch(apiUrl, { method: "GET", signal: AbortSignal.timeout(5000) });
62	    const data = await response.json();
63	    if (data.status === "ok") {
64	      elements.statusBadge.classList.remove("offline");
65	      elements.statusBadge.innerHTML = '<span class="status-dot"></span><span>Online</span>';
66	    } else {
67	      setOffline();
68	    }
69	  } catch {
70	    setOffline();
71	  }
72	}
73	
74	function setOffline() {
75	  elements.statusBadge.classList.add("offline");
76	  elements.statusBadge.innerHTML = '<span class="status-dot"></span><span>Offline</span>';
77	}
78	
79	// ---- ANALYZE ----
80	elements.analyzeBtn.addEventListener("click", async () => {
81	  const text = elements.emailText.value.trim();
82	
83	  if (!text) {
84	    shakeButton();
85	    return;
86	  }
87	
88	  // Start loading
89	  elements.analyzeBtn.classList.add("loading");
90	  elements.resultCard.classList.add("hidden");
91	
92	  try {
93	    const apiUrl = await getApiUrl();
94	    const response = await fetch(`${apiUrl}/predict`, {
95	      method: "POST",
96	      headers: { "Content-Type": "application/json" },
97	      body: JSON.stringify({ text }),
98	    });
99	
100	    if (!response.ok) {
101	      throw new Error(`API error: ${response.status}`);
102	    }
103	
104	    const data = await response.json();
105	    showResult(data);
106	    saveToHistory(text, data);
107	  } catch (err) {
108	    showError(err.message);
109	  } finally {
110	    elements.analyzeBtn.classList.remove("loading");
111	  }
112	});
113	
114	// ---- SHOW RESULT ----
115	function showResult(data) {
116	  const isSpam = data.prediction === "spam";
117	
118	  elements.resultCard.classList.remove("hidden");
119	  elements.resultHeader.className = `result-header ${isSpam ? "spam" : "genuine"}`;
120	  elements.resultIcon.textContent = isSpam ? "🚨" : "✅";
121	  elements.resultLabel.textContent = isSpam ? "Spam Detected" : "Genuine Email";
122	
123	  // Confidence bar
124	  elements.confidenceBar.className = `confidence-bar ${isSpam ? "spam" : "genuine"}`;
125	  setTimeout(() => {
126	    elements.confidenceBar.style.width = `${data.confidence}%`;
127	  }, 100);
128	  elements.confidenceText.textContent = `${data.confidence}%`;
129	  elements.confidenceText.style.color = isSpam ? "var(--accent-red)" : "var(--accent-green)";
130	
131	  // Trigger words
132	  if (data.trigger_words && data.trigger_words.length > 0) {
133	    elements.triggerWords.classList.remove("hidden");
134	    elements.triggerTags.innerHTML = data.trigger_words
135	      .map((w) => `<span class="trigger-tag">${w}</span>`)
136	      .join("");
137	  } else {
138	    elements.triggerWords.classList.add("hidden");
139	  }
140	}
141	
142	// ---- SHOW ERROR ----
143	function showError(message) {
144	  elements.resultCard.classList.remove("hidden");
145	  elements.resultHeader.className = "result-header spam";
146	  elements.resultIcon.textContent = "⚠️";
147	  elements.resultLabel.textContent = "Connection Error";
148	  elements.confidenceBar.style.width = "0%";
149	  elements.confidenceText.textContent = message;
150	  elements.confidenceText.style.color = "var(--accent-red)";
151	  elements.triggerWords.classList.add("hidden");
152	}
153	
154	// ---- SHAKE ANIMATION ----
155	function shakeButton() {
156	  elements.analyzeBtn.style.animation = "shake 0.4s ease";
157	  setTimeout(() => {
158	    elements.analyzeBtn.style.animation = "";
159	  }, 400);
160	}
161	
162	// ---- HISTORY ----
163	async function saveToHistory(text, data) {
164	  const history = await getHistory();
165	  history.unshift({
166	    text: text.substring(0, 100),
167	    prediction: data.prediction,
168	    confidence: data.confidence,
169	    timestamp: new Date().toLocaleString(),
170	  });
171	
172	  // Keep last 20
173	  if (history.length > 20) history.pop();
174	
175	  if (typeof chrome !== "undefined" && chrome.storage) {
176	    chrome.storage.local.set({ scanHistory: history });
177	  }
178	  renderHistory(history);
179	}
180	
181	async function getHistory() {
182	  return new Promise((resolve) => {
183	    if (typeof chrome !== "undefined" && chrome.storage) {
184	      chrome.storage.local.get(["scanHistory"], (result) => {
185	        resolve(result.scanHistory || []);
186	      });
187	    } else {
188	      resolve([]);
189	    }
190	  });
191	}
192	
193	function renderHistory(history) {
194	  if (!history.length) {
195	    elements.historyList.innerHTML = `
196	      <div class="empty-state">
197	        <span class="empty-icon">📭</span>
198	        <p>No scans yet. Analyze an email to see results here.</p>
199	      </div>`;
200	    return;
201	  }
202	
203	  elements.historyList.innerHTML = history
204	    .map(
205	      (item) => `
206	    <div class="history-item">
207	      <div class="history-badge ${item.prediction}">
208	        ${item.prediction === "spam" ? "🚨" : "✅"}
209	      </div>
210	      <div class="history-info">
211	        <div class="history-text">${escapeHtml(item.text)}</div>
212	        <div class="history-meta">${item.prediction.toUpperCase()} • ${item.confidence}% • ${item.timestamp}</div>
213	      </div>
214	    </div>`
215	    )
216	    .join("");
217	}
218	
219	elements.clearHistory.addEventListener("click", () => {
220	  if (typeof chrome !== "undefined" && chrome.storage) {
221	    chrome.storage.local.set({ scanHistory: [] });
222	  }
223	  renderHistory([]);
224	});
225	
226	// ---- SETTINGS ----
227	elements.saveSettings.addEventListener("click", async () => {
228	  const url = elements.apiUrl.value.trim().replace(/\/+$/, ""); // remove trailing slash
229	  if (typeof chrome !== "undefined" && chrome.storage) {
230	    chrome.storage.local.set({ apiUrl: url || DEFAULT_API_URL });
231	  }
232	  elements.saveToast.classList.remove("hidden");
233	  setTimeout(() => elements.saveToast.classList.add("hidden"), 2500);
234	
235	  // Re-check API status
236	  checkApiStatus();
237	});
238	
239	// ---- LOAD SETTINGS ----
240	async function loadSettings() {
241	  const url = await getApiUrl();
242	  elements.apiUrl.value = url;
243	}
244	
245	// ---- ESCAPE HTML ----
246	function escapeHtml(str) {
247	  const div = document.createElement("div");
248	  div.textContent = str;
249	  return div.innerHTML;
250	}
