78	/* ---- RESULT OVERLAY ---- */
79	.ssd-overlay {
80	  position: fixed;
81	  top: 20px;
82	  right: 20px;
83	  z-index: 9999999;
84	  width: 380px;
85	  max-width: calc(100vw - 40px);
86	  border-radius: 16px;
87	  overflow: hidden;
88	  font-family: 'Google Sans', 'Segoe UI', Roboto, Arial, sans-serif;
89	  animation: ssd-overlay-enter 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
90	}
91	
92	@keyframes ssd-overlay-enter {
93	  0% {
94	    opacity: 0;
95	    transform: translateX(40px) scale(0.95);
96	  }
97	  100% {
98	    opacity: 1;
99	    transform: translateX(0) scale(1);
100	  }
101	}
102	
103	.ssd-overlay.ssd-closing {
104	  animation: ssd-overlay-exit 0.3s ease forwards;
105	}
106	
107	@keyframes ssd-overlay-exit {
108	  to {
109	    opacity: 0;
110	    transform: translateX(30px) scale(0.95);
111	  }
112	}
